import sys
input = sys.stdin.readline

def query(a):
    print('?', *a, flush=True)
    return int(input())

def solve():
    n = int(input())
    p = [0] * (n + 1)  # p[i] = value at position i, 1-indexed

    # Query type A for position i: a_i=2, a_j=1 for j!=i
    # s_i = p_i+2, s_j = p_j+1 for j!=i
    # duplicate iff p_j = p_i+1 for some j!=i
    # answer=0 => p_i=n
    # answer=min(i, pos(p_i+1)) otherwise

    # Query type B for position i: a_i=1, a_j=2 for j!=i  
    # s_i=p_i+1, s_j=p_j+2 for j!=i
    # duplicate iff p_j=p_i-1 for some j!=i
    # answer=0 => p_i=1

    succ = {}  # succ[i] = j means pos(p_i+1)=j (p_j = p_i+1)
    pred = {}  # pred[i] = j means pos(p_i-1)=j (p_j = p_i-1)

    for i in range(1, n+1):
        a = [1] * n
        a[i-1] = 2
        r = query(a)
        if r == 0:
            p[i] = n
        elif r == i:
            # pos(p_i+1) > i, successor is to the right
            succ[i] = None  # unknown position, but > i
        else:
            # r < i, pos(p_i+1) = r
            succ[i] = r

    for i in range(1, n+1):
        a = [2] * n
        a[i-1] = 1
        r = query(a)
        if r == 0:
            p[i] = 1
        elif r == i:
            pred[i] = None
        else:
            pred[i] = r

    # Build chains: find position of n (already known), trace down
    # Also use pred info
    for i in range(1, n+1):
        if i in succ and succ[i] is not None:
            j = succ[i]
            if p[i] != 0 and p[j] == 0:
                p[j] = p[i] + 1
        if i in pred and pred[i] is not None:
            j = pred[i]
            if p[i] != 0 and p[j] == 0:
                p[j] = p[i] - 1

    # Iteratively fill in
    changed = True
    while changed:
        changed = False
        for i in range(1, n+1):
            if p[i] == 0:
                continue
            if i in succ and succ[i] is not None:
                j = succ[i]
                if p[j] == 0:
                    p[j] = p[i] + 1
                    changed = True
            if i in pred and pred[i] is not None:
                j = pred[i]
                if p[j] == 0:
                    p[j] = p[i] - 1
                    changed = True

    # Fill remaining using known values
    known_vals = set(v for v in p[1:] if v != 0)
    remaining_vals = [v for v in range(1, n+1) if v not in known_vals]
    remaining_pos = [i for i in range(1, n+1) if p[i] == 0]
    for pos, val in zip(remaining_pos, remaining_vals):
        p[pos] = val

    print('!', *p[1:], flush=True)

